SELECT *
FROM algorithm_performance
WHERE performance_id = 100 AND algorithm_id = 1;

SELECT performance_id, algorithm_id, x_axis, ur_accuracy, rs_accuracy
FROM algorithm_performance
WHERE test_date > '2023-01-01' AND test_environment = 'Production';

SELECT AVG(request_duration) AS avg_duration, MAX(request_duration) AS max_duration, MIN(request_duration) AS min_duration 
FROM access_logs 
WHERE performance_id IN (SELECT performance_id FROM algorithm_performance WHERE algorithm_id = 1);

SELECT ap.ur_accuracy, ap.ur_fairness 
FROM algorithm_performance AS ap
WHERE ap.algorithm_id > 5 AND ap.x_axis > 5;

SELECT AL.algorithm_name, AP.test_date, AP.algorithm_id
FROM algorithm_performance AS AP
JOIN algorithms AS AL ON AP.algorithm_id = AL.algorithm_id;

SELECT *
FROM algorithm_performance AS ap
WHERE ap.rs_accuracy > 60 AND ap.test_environment = 'development';
